// src/router/AppRouter.jsx
// Define todas las rutas y protege las páginas privadas.
// Si el usuario no está logueado, lo redirige a /login.

import { BrowserRouter, Routes, Route, Navigate, Outlet } from 'react-router-dom'
import { useAuth }    from '../context/AuthContext'
import Navbar         from '../components/layout/Navbar'
import Sidebar        from '../components/layout/Sidebar'
import Login          from '../pages/Login'
import Dashboard      from '../pages/Dashboard'
import Transactions   from '../pages/Transactions'
import Budget         from '../pages/Budget'

// Wrapper para rutas protegidas: muestra el layout completo
const PrivateLayout = () => {
  const { isAuth } = useAuth()
  if (!isAuth) return <Navigate to="/login" replace />

  return (
    <div className="app-shell">
      <Navbar />
      <Sidebar />
      <main className="main-content">
        <Outlet /> {/* Aquí se renderiza la página activa */}
      </main>
    </div>
  )
}

export default function AppRouter() {
  return (
    <BrowserRouter>
      <Routes>
        {/* Ruta pública */}
        <Route path="/login" element={<Login />} />

        {/* Rutas privadas — todas usan el layout con Navbar + Sidebar */}
        <Route element={<PrivateLayout />}>
          <Route path="/"             element={<Dashboard />} />
          <Route path="/transactions" element={<Transactions />} />
          <Route path="/budget"       element={<Budget />} />
        </Route>

        {/* Cualquier ruta desconocida redirige al dashboard */}
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </BrowserRouter>
  )
}
